function lastNonZero(a) {
  let i = a.length - 1;
  while (i >= 0 && a[i] === 0) i--;
  return i;
}

function partitionEvenOdd(a) {
  let w = 0;
  for (let i = 0; i < a.length; i++) {
    if (a[i] % 2 === 0) {
      [a[w], a[i]] = [a[i], a[w]];
      w++;
    }
  }
  return a;
}

