function sortedIntersection(A, B) {
  let i = 0, j = 0;
  const out = [];
  while (i < A.length && j < B.length) {
    if (A[i] === B[j]) { out.push(A[i]); i++; j++; }
    else if (A[i] < B[j]) i++;
    else j++;
  }
  return out;
}

function compress(s) {
  let i = 0;
  let res = '';
  while (i < s.length) {
    let j = i;
    while (j < s.length && s[j] === s[i]) j++;
    res += s[i];
    if (j - i > 1) res += (j - i);
    i = j;
  }
  return res;
}

